#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool solve(vector<int>& nodes) {
        int n = nodes.size();
        for (int i = 0; i < n; ++i) {
            int val = nodes[i];
            if (val == -1) continue; // null node, skip
            long long left_contrib = 0, right_contrib = 0;
            int left_idx = 2 * i + 1;
            int right_idx = 2 * i + 2;
            bool hasLeft = left_idx < n && nodes[left_idx] != -1;
            bool hasRight = right_idx < n && nodes[right_idx] != -1;
            // leaf check: no existing children
            if (!hasLeft && !hasRight) continue;
            if (hasLeft) left_contrib = nodes[left_idx];
            if (hasRight) right_contrib = nodes[right_idx];
            if ((long long)val != left_contrib + right_contrib) return false;
        }
        return true;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N;
    if (!(cin >> N)) return 0;
    vector<int> nodes(N);
    for (int i = 0; i < N; ++i) cin >> nodes[i];
    Solution sol;
    bool ok = sol.solve(nodes);
    cout << (ok ? "YES" : "NO") << "\n";
    return 0;
}
